import{_ as e,o as i,c as l,ag as t}from"./chunks/framework.CAXxHpAX.js";const _=JSON.parse('{"title":"机器学习基础","description":"","frontmatter":{},"headers":[],"relativePath":"machine-learning/basics.md","filePath":"machine-learning/basics.md","lastUpdated":1777200285000}'),r={name:"machine-learning/basics.md"};function n(o,a,s,c,h,d){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="机器学习基础" tabindex="-1">机器学习基础 <a class="header-anchor" href="#机器学习基础" aria-label="Permalink to &quot;机器学习基础&quot;">​</a></h1><h2 id="一句话理解" tabindex="-1">一句话理解 <a class="header-anchor" href="#一句话理解" aria-label="Permalink to &quot;一句话理解&quot;">​</a></h2><p>机器学习是让模型从数据中学习规律，并在未见过的数据上做出预测或决策。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><ul><li>训练集：用于训练模型参数。</li><li>验证集：用于调参和选择模型。</li><li>测试集：用于最终评估泛化能力。</li><li>泛化能力：模型在新数据上的表现。</li><li>过拟合：训练集表现好，验证集或测试集表现差。</li><li>欠拟合：训练集和验证集表现都不好。</li></ul><h2 id="常考点" tabindex="-1">常考点 <a class="header-anchor" href="#常考点" aria-label="Permalink to &quot;常考点&quot;">​</a></h2><ul><li>测试集用于最终评估模型的泛化能力。</li><li>训练误差和验证误差都很高，通常说明模型欠拟合。</li><li>训练误差低而验证误差高，通常说明模型过拟合。</li></ul><h2 id="易错点" tabindex="-1">易错点 <a class="header-anchor" href="#易错点" aria-label="Permalink to &quot;易错点&quot;">​</a></h2><ul><li>验证集不是最终评估集。</li><li>模型在训练集准确率高，不代表泛化能力强。</li></ul>',9)])])}const m=e(r,[["render",n]]);export{_ as __pageData,m as default};
